const query = $input.first().json.query || {};
const name = (query.name || '').trim();

if (!name || name.length < 2) {
  return [{ json: { skip: true, error: 'Need at least 2 characters', name: name } }];
}

// Default range: 2 years back, 2 years forward
const now = new Date();
const pastYears = parseInt(query.pastYears) || 2;
const futureYears = parseInt(query.futureYears) || 2;

const start = new Date(now);
start.setFullYear(start.getFullYear() - pastYears);
start.setHours(0, 0, 0, 0);

const end = new Date(now);
end.setFullYear(end.getFullYear() + futureYears);
end.setHours(23, 59, 59, 999);

return [{
  json: {
    name: name,
    normalizedName: name.toLowerCase().trim(),
    startDate: start.toISOString(),
    endDate: end.toISOString(),
    skip: false
  }
}];

const events = $input.all();
const params = $('Parse Parameters').first().json;
const normalizedName = params.normalizedName;

const colorIdToName = {
  '10': 'green', '9': 'blue', '11': 'red', '5': 'yellow',
  '3': 'purple', '6': 'orange', '4': 'pink', '8': 'gray'
};

const statusLabelToValue = {
  'чакащ': 'pending', 'потвърден': 'confirmed', 'завършен': 'completed'
};

function toSofiaTime(isoString) {
  if (!isoString) return null;
  const date = new Date(isoString);
  const options = {
    timeZone: 'Europe/Sofia',
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', hour12: false
  };
  const formatter = new Intl.DateTimeFormat('en-CA', options);
  const parts = formatter.formatToParts(date);
  const getPart = (type) => parts.find(p => p.type === type)?.value || '00';
  return {
    date: `${getPart('year')}-${getPart('month')}-${getPart('day')}`,
    time: `${getPart('hour')}:${getPart('minute')}`
  };
}

const nowIso = new Date().toISOString();
const transformed = [];

for (const item of events) {
  const event = item.json;
  const rawTitle = (event.summary || '').replace(/^⏳\s*/, '');

  // Match: title must contain the search term (case-insensitive)
  if (!rawTitle.toLowerCase().includes(normalizedName)) continue;

  const startDateTime = event.start?.dateTime || event.start?.date;
  const endDateTime = event.end?.dateTime || event.end?.date;
  let startDate, startTime, endDate, endTime, isAllDay = false;

  if (event.start?.date) {
    isAllDay = true;
    startDate = event.start.date;
    endDate = event.end.date;
    startTime = '00:00';
    endTime = '23:59';
  } else {
    const s = toSofiaTime(startDateTime);
    const e = toSofiaTime(endDateTime);
    startDate = s.date; startTime = s.time;
    endDate = e.date; endTime = e.time;
  }

  const duration = Math.round((new Date(endDateTime) - new Date(startDateTime)) / 60000);
  const description = event.description || '';
  let phone = '', procedure = '', appointmentStatus = 'confirmed';

  const phoneMatch = description.match(/(?:тел|phone|📞)[:\s]*([+\d\s-]+)/i);
  if (phoneMatch) phone = phoneMatch[1].trim();
  const procMatch = description.match(/(?:процедура|procedure|🦷)[:\s]*(.+?)(?:\n|$)/i);
  if (procMatch) procedure = procMatch[1].trim();
  const statusMatch = description.match(/(?:📋 Статус|статус)[:\s]*(.+?)(?:\n|$)/i);
  if (statusMatch) {
    const rawStatus = statusMatch[1].trim().toLowerCase();
    appointmentStatus = statusLabelToValue[rawStatus] || rawStatus;
  }
  if ((event.summary || '').startsWith('⏳')) appointmentStatus = 'pending';

  const isPast = startDateTime < nowIso;

  transformed.push({
    id: event.id,
    googleEventId: event.id,
    title: rawTitle || 'Без заглавие',
    patientName: rawTitle || '',
    patientPhone: phone,
    procedure: procedure,
    description: description,
    date: startDate,
    startTime: startTime,
    endTime: endTime,
    endDate: endDate,
    duration: duration,
    isAllDay: isAllDay,
    colorId: colorIdToName[event.colorId] || 'green',
    status: appointmentStatus,
    isPast: isPast,
    location: event.location || '',
    htmlLink: event.htmlLink
  });
}

// Sort: upcoming first (asc), then past (desc)
transformed.sort((a, b) => {
  const aDt = `${a.date}T${a.startTime}`;
  const bDt = `${b.date}T${b.startTime}`;
  if (a.isPast && !b.isPast) return 1;
  if (!a.isPast && b.isPast) return -1;
  if (a.isPast && b.isPast) return bDt.localeCompare(aDt); // past: newest first
  return aDt.localeCompare(bDt); // upcoming: soonest first
});

return [{
  json: {
    success: true,
    name: params.name,
    count: transformed.length,
    appointments: transformed
  }
}];
